#include <stdio.h>
#define MOD 1000000007
int main() {
    int N, Q;
    scanf("%d", &N);
    int F[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &F[i]);
    }
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        int type;
        scanf("%d", &type);
        if (type == 1) {
            int p, f;
            scanf("%d %d", &p, &f);
            F[p - 1] = f;
        } else {
            int R;
            scanf("%d", &R);
            long long enjoyment = 1;
            for (int j = 0; j < N; j += R) {
                if (j + 1 > N) break;
                enjoyment = (enjoyment * F[j]) % MOD;
            }
            printf("%lld %lld\n", enjoyment / (MOD * 10), enjoyment % MOD);
        }
    }
    return 0;
}

