import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int[] F = new int[N];
        for (int i = 0; i < N; i++) {
            F[i] = sc.nextInt();
        }
        int Q = sc.nextInt();
        for (int i = 0; i < Q; i++) {
            int type = sc.nextInt();
            if (type == 1) {
                int p = sc.nextInt();
                int f = sc.nextInt();
                F[p - 1] = f;
            } else {
                int R = sc.nextInt();
                long enjoyment = 1;
                for (int j = 0; j < N; j += R) {
                    if (j + 1 > N) break;
                    enjoyment = (enjoyment * F[j]) % 1000000007;
                }
                System.out.println(enjoyment / (1000000007 * 10) + " " + enjoyment % 1000000007);
            }
        }
    }
}

