const F = input[idx++].split(' ').map(x => parseInt(x));
const Q = parseInt(input[idx++]);
for (let i = 0; i < Q; i++) {
    const [type, ...args] = input[idx++].split(' ').map(x => parseInt(x));
    if (type === 1) {
        const p = args[0];
        const f = args[1];
        F[p - 1] = f;
    } else {
        const R = args[0];
        let enjoyment = 1;
        for (let j = 0; j < N; j += R) {
            if (j + 1 > N) break;
            enjoyment = (enjoyment * F[j]) % MOD;
        }
        console.log(Math.floor(enjoyment / (MOD * 10)), enjoyment % MOD);
    }
}
